export default function AppRouter() {
  return (
    <Router basename="/">
         <div>
    <ul>
     <li><Link to="/">Home</Link></li>
     <li><Link to="/about">About</Link></li>
    </ul>
    <hr />
    <Route exact path="/science" component={Science} />
    <Route path="/about" component={About} />
    <Route path="/design" component={ Design } />
   </div>
      

    </Router>
  );
}

